import{_ as e,o,c as a,ag as r}from"./chunks/framework.D4O_uTxf.js";const p=JSON.parse('{"title":"CIV Project Governance Summary","description":"","frontmatter":{},"headers":[],"relativePath":"governance/GOVERNANCE_SUMMARY.md","filePath":"governance/GOVERNANCE_SUMMARY.md","lastUpdated":1771844172000}'),n={name:"governance/GOVERNANCE_SUMMARY.md"};function i(s,t,l,d,c,g){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="civ-project-governance-summary" tabindex="-1">CIV Project Governance Summary <a class="header-anchor" href="#civ-project-governance-summary" aria-label="Permalink to &quot;CIV Project Governance Summary&quot;">​</a></h1><p><strong>Date:</strong> 2026-02-21</p><p><strong>Status:</strong> Aligned with kush ecosystem standards</p><p>This document consolidates all governance policies, quality gates, and traceability requirements for the CIV city simulation engine.</p><hr><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ol><li><a href="#specification-driven-workflow">Specification-Driven Workflow</a></li><li><a href="#quality-governance">Quality Governance</a></li><li><a href="#determinism--replay-requirements">Determinism &amp; Replay Requirements</a></li><li><a href="#anti-drift-rules">Anti-Drift Rules</a></li><li><a href="#cross-track-integration">Cross-Track Integration</a></li><li><a href="#governance-documents-map">Governance Documents Map</a></li></ol><hr><h2 id="specification-driven-workflow" tabindex="-1">Specification-Driven Workflow <a class="header-anchor" href="#specification-driven-workflow" aria-label="Permalink to &quot;Specification-Driven Workflow&quot;">​</a></h2><h3 id="core-process" tabindex="-1">Core Process <a class="header-anchor" href="#core-process" aria-label="Permalink to &quot;Core Process&quot;">​</a></h3><p>All substantial changes to CIV must:</p><ol><li><strong>Start with specs</strong> — Identify affected specs in <code>docs/specs/</code></li><li><strong>Update specs first</strong> — Record assumptions, invariants, design decisions</li><li><strong>Implement code</strong> — Link code back to spec IDs/sections via comments</li><li><strong>Pass quality gates</strong> — All tests, linters, complexity checks</li><li><strong>Brief changelog</strong> — One-line entry explaining the change</li></ol><h3 id="civ-specification-package-9-specs" tabindex="-1">CIV Specification Package (9 Specs) <a class="header-anchor" href="#civ-specification-package-9-specs" aria-label="Permalink to &quot;CIV Specification Package (9 Specs)&quot;">​</a></h3><p>All specifications are located in <code>docs/specs/CIV-*.md</code> and are marked <strong>CLOSED</strong>:</p><table tabindex="0"><thead><tr><th>ID</th><th>Title</th><th>Summary</th></tr></thead><tbody><tr><td><strong>CIV-0001</strong></td><td>Core Simulation Loop</td><td>Foundation: tick-based state transitions, deterministic event ordering, replay contract</td></tr><tr><td><strong>CIV-0100</strong></td><td>Economy Spec v1</td><td>Ledger model, market clearing, double-entry accounting, conservation invariants</td></tr><tr><td><strong>CIV-0101</strong></td><td>Two-Zoom LOD v1</td><td>Spatial representation, hierarchical level-of-detail (macro/micro), city districts</td></tr><tr><td><strong>CIV-0102</strong></td><td>Climate Follow-up v1</td><td>Energy accounting integration, supply-stress metrics, demand-response mechanics</td></tr><tr><td><strong>CIV-0103</strong></td><td>Institutions, Time-Series, Citizen Lifecycle v1</td><td>Actor lifecycle model, institutional state machine, time-series citizen metrics</td></tr><tr><td><strong>CIV-0104</strong></td><td>Minimal Constraint Set Theorem</td><td>Mathematical foundations for determinism, idempotency, and replay semantics</td></tr><tr><td><strong>CIV-0105</strong></td><td>War, Diplomacy, Shadow Networks v1</td><td>Geopolitical dynamics, conflict resolution, institutional coalitions</td></tr><tr><td><strong>CIV-0106</strong></td><td>Social, Ideology, Health, Insurgency v1</td><td>Citizen agency, emergent conflict, health systems, social cohesion</td></tr><tr><td><strong>CIV-0107</strong></td><td>Joule Economy System v1</td><td>Agent-centric resource allocation, joule accumulation, work capacity modeling</td></tr></tbody></table><p><strong>Required Spec Sections:</strong></p><ul><li>Summary (one-paragraph overview)</li><li>CIV Sim Integration Notes (how this spec relates to other modules)</li></ul><p>Verify with: <code>task spec:validate</code> or <code>task spec:list</code></p><hr><h2 id="quality-governance" tabindex="-1">Quality Governance <a class="header-anchor" href="#quality-governance" aria-label="Permalink to &quot;Quality Governance&quot;">​</a></h2><h3 id="configuration-reference" tabindex="-1">Configuration Reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to &quot;Configuration Reference&quot;">​</a></h3><p><strong>File:</strong> <code>qa-config.json</code></p><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th><th>Scope</th></tr></thead><tbody><tr><td><strong>Test Coverage</strong></td><td>≥ 80%</td><td>All code paths</td></tr><tr><td><strong>Cyclomatic Complexity</strong></td><td>≤ 10 per function</td><td>rust (cargo-clippy)</td></tr><tr><td><strong>Cognitive Complexity</strong></td><td>≤ 15 per function</td><td>rust (cargo-clippy)</td></tr><tr><td><strong>Function Lines</strong></td><td>≤ 60 max</td><td>rust</td></tr><tr><td><strong>Code Duplication</strong></td><td>≤ 8%</td><td>Across codebase</td></tr></tbody></table><h3 id="quality-gates" tabindex="-1">Quality Gates <a class="header-anchor" href="#quality-gates" aria-label="Permalink to &quot;Quality Gates&quot;">​</a></h3><p><strong>File:</strong> <code>docs/governance/QUALITY_GATES.md</code></p><p>Run via <code>task quality</code>:</p><ol><li><code>cargo fmt --all</code> — Code formatting</li><li><code>cargo check</code> — Compilation check</li><li><code>cargo test</code> — Unit + integration tests</li><li><code>cargo clippy --workspace --all-targets -- -D warnings</code> — Lint with warnings-as-errors</li><li><code>task spec:validate</code> — Spec completeness check</li><li><code>task docs:lint</code> — Markdown linting</li></ol><p><strong>Before finalizing any work</strong>, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">task</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quality</span></span></code></pre></div><h3 id="enforcement" tabindex="-1">Enforcement <a class="header-anchor" href="#enforcement" aria-label="Permalink to &quot;Enforcement&quot;">​</a></h3><ul><li><strong>Pre-write hooks:</strong> All markdown must pass linting before commit</li><li><strong>Suppressions:</strong> Zero new suppressions without inline justification (syntax: <code># noqa: CODE -- reason</code>)</li><li><strong>Code reviews:</strong> All PRs must have passing quality gates</li><li><strong>CI integration:</strong> Continuous integration rejects non-conforming commits</li></ul><hr><h2 id="determinism-replay-requirements" tabindex="-1">Determinism &amp; Replay Requirements <a class="header-anchor" href="#determinism-replay-requirements" aria-label="Permalink to &quot;Determinism &amp; Replay Requirements&quot;">​</a></h2><h3 id="core-mandate" tabindex="-1">Core Mandate <a class="header-anchor" href="#core-mandate" aria-label="Permalink to &quot;Core Mandate&quot;">​</a></h3><p><strong>All CIV simulation logic must be deterministic and replayable.</strong></p><ul><li><strong>No silent randomness:</strong> All RNG calls must be seeded and logged</li><li><strong>All external effects:</strong> Side effects must be explicit (database writes, file I/O, API calls)</li><li><strong>Replay guarantee:</strong> Same input state + same seed → same output state, deterministically</li><li><strong>See:</strong> <code>CIV-0001</code> (Core Simulation Loop) and <code>CIV-0104</code> (Minimal Constraint Set Theorem)</li></ul><h3 id="implementation-practices" tabindex="-1">Implementation Practices <a class="header-anchor" href="#implementation-practices" aria-label="Permalink to &quot;Implementation Practices&quot;">​</a></h3><ol><li><strong>Seed state logging</strong> — Every stochastic step logs: <code>(seed, rng_state_before, decision, rng_state_after)</code></li><li><strong>Event ordering</strong> — Core loop specifies tick order: climate → economy → institutions → actors → conflicts</li><li><strong>Idempotency keys</strong> — All state mutations include <code>(tick, actor_id, decision_id)</code> for uniqueness</li><li><strong>Audit trail</strong> — All policy decisions emit immutable events to <code>events/</code> log</li></ol><h3 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h3><ul><li><strong>Replay tests:</strong> Run simulation N times; assert identical event log each time</li><li><strong>Determinism validator:</strong> Tool to replay simulation from event log; compare states</li><li><strong>See:</strong> <code>TRACEABILITY_MATRIX.md</code> for test→spec linkage</li></ul><hr><h2 id="anti-drift-rules" tabindex="-1">Anti-Drift Rules <a class="header-anchor" href="#anti-drift-rules" aria-label="Permalink to &quot;Anti-Drift Rules&quot;">​</a></h2><p><strong>All rules inherited from kush ecosystem global CLAUDE.md.</strong></p><h3 id="forbidden-patterns" tabindex="-1">Forbidden Patterns <a class="header-anchor" href="#forbidden-patterns" aria-label="Permalink to &quot;Forbidden Patterns&quot;">​</a></h3><ol><li><strong>No Fallbacks</strong> — Never add <code>try: new() except: old()</code></li><li><strong>No Legacy Compat</strong> — Never add flags like <code>if legacy_mode: old() else: new()</code></li><li><strong>No Silent Failures</strong> — Never swallow exceptions or return defaults</li><li><strong>No Backwards Compat</strong> — Zero user debt. All changes are breaking.</li><li><strong>No &quot;Just In Case&quot; Code</strong> — Only add code that&#39;s immediately needed</li></ol><h3 id="correct-approach" tabindex="-1">Correct Approach <a class="header-anchor" href="#correct-approach" aria-label="Permalink to &quot;Correct Approach&quot;">​</a></h3><ul><li><strong>Fail fast, fail loud</strong> — Code should stop and print stack traces, not hide errors</li><li><strong>Fix root causes</strong> — If something fails, fix it; don&#39;t work around it</li><li><strong>Verify parity</strong> — Before removing code, verify feature parity with new implementation</li></ul><p><strong>Reference:</strong> <code>/Users/kooshapari/temp-PRODVERCEL/485/kush/civ/docs/upstream-governance/thegent/CLAUDE.md</code> (Section: &quot;FORBIDDEN: Fallbacks...&quot;)</p><hr><h2 id="cross-track-integration" tabindex="-1">Cross-Track Integration <a class="header-anchor" href="#cross-track-integration" aria-label="Permalink to &quot;Cross-Track Integration&quot;">​</a></h2><h3 id="venture-platform" tabindex="-1">Venture Platform <a class="header-anchor" href="#venture-platform" aria-label="Permalink to &quot;Venture Platform&quot;">​</a></h3><p>CIV integrates with the Venture autonomous agent platform at these points:</p><table tabindex="0"><thead><tr><th>CIV Component</th><th>Venture Component</th><th>Integration Point</th><th>Spec Reference</th></tr></thead><tbody><tr><td><strong>CIV-0100 Economy Events</strong></td><td>Venture EventEnvelopeV1</td><td>Event streaming with trace IDs</td><td>TRACK_C_CONTROL_PLANE.md</td></tr><tr><td><strong>CIV-0103 Institutions</strong></td><td>Venture Compliance Machine</td><td>Audit trail for institutional changes</td><td>OPS_COMPLIANCE_SPEC.md</td></tr><tr><td><strong>CIV-0102 Energy Accounting</strong></td><td>Venture Spend Quotas</td><td>Conservation equation maps to budget model</td><td>TRACK_B_TREASURY_COMPLIANCE_SPEC.md</td></tr><tr><td><strong>CIV-0001 Policy.Evaluate</strong></td><td>Venture Tool Allowlist</td><td>Rate-limited tool calls with EAU budget</td><td>TRACK_C_CONTROL_PLANE.md</td></tr></tbody></table><p><strong>Cross-Track Spec Index:</strong> <code>/Users/kooshapari/temp-PRODVERCEL/485/kush/parpour/SPECS_INDEX.md</code></p><h3 id="planning-workspace" tabindex="-1">Planning Workspace <a class="header-anchor" href="#planning-workspace" aria-label="Permalink to &quot;Planning Workspace&quot;">​</a></h3><p>All implementation work tracked in:</p><ul><li><strong>Immediate next steps:</strong> <code>/Users/kooshapari/temp-PRODVERCEL/485/kush/parpour/NEXT_STEPS.md</code></li><li><strong>CIV work stream:</strong> <code>docs/reference/WORK_STREAM.md</code> (this project)</li></ul><hr><h2 id="governance-documents-map" tabindex="-1">Governance Documents Map <a class="header-anchor" href="#governance-documents-map" aria-label="Permalink to &quot;Governance Documents Map&quot;">​</a></h2><h3 id="in-this-project" tabindex="-1">In This Project <a class="header-anchor" href="#in-this-project" aria-label="Permalink to &quot;In This Project&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th><th>Audience</th></tr></thead><tbody><tr><td><strong>CLAUDE.md</strong></td><td>Project governance index + guardrails</td><td>Developers, agents</td></tr><tr><td><strong>AGENTS.md</strong></td><td>Agent mandate for CIV work</td><td>Agents, project managers</td></tr><tr><td><strong>Taskfile.yml</strong></td><td>Task definitions (cargo, linters, spec checks)</td><td>All</td></tr><tr><td><strong>qa-config.json</strong></td><td>Quality gate thresholds</td><td>CI, linters</td></tr><tr><td><strong>QUALITY_GATES.md</strong></td><td>Quality gate definitions (this file)</td><td>Developers</td></tr><tr><td><strong>GOVERNANCE_SUMMARY.md</strong></td><td>Unified governance reference (you are here)</td><td>All</td></tr><tr><td><strong>docs/reference/WORK_STREAM.md</strong></td><td>Active work items + status</td><td>Project managers, developers</td></tr><tr><td><strong>docs/reference/TRACEABILITY_MATRIX.md</strong></td><td>FR → Spec → Code linkage</td><td>QA, auditors</td></tr></tbody></table><h3 id="upstream-global-ecosystem" tabindex="-1">Upstream (Global/Ecosystem) <a class="header-anchor" href="#upstream-global-ecosystem" aria-label="Permalink to &quot;Upstream (Global/Ecosystem)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>docs/upstream-governance/thegent/CLAUDE.md</code></td><td>Global kush ecosystem rules</td></tr><tr><td><code>/Users/kooshapari/kush/trace/CLAUDE.md</code></td><td>trace project reference standard</td></tr><tr><td><code>/Users/kooshapari/kush/trace/quality-gate.yml</code></td><td>Reference quality-gate config</td></tr></tbody></table><h3 id="parpour-planning-workspace" tabindex="-1">Parpour Planning Workspace <a class="header-anchor" href="#parpour-planning-workspace" aria-label="Permalink to &quot;Parpour Planning Workspace&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>/Users/kooshapari/temp-PRODVERCEL/485/kush/parpour/SPECS_INDEX.md</code></td><td>Master spec index (CIV + Venture)</td></tr><tr><td><code>/Users/kooshapari/temp-PRODVERCEL/485/kush/parpour/NEXT_STEPS.md</code></td><td>Cross-track implementation roadmap</td></tr></tbody></table><hr><h2 id="execution-checklist" tabindex="-1">Execution Checklist <a class="header-anchor" href="#execution-checklist" aria-label="Permalink to &quot;Execution Checklist&quot;">​</a></h2><p>Before pushing code or opening PRs:</p><ul><li>[ ] <code>task spec:validate</code> passes</li><li>[ ] <code>task quality</code> passes (fmt, check, test, clippy, spec:validate, docs:lint)</li><li>[ ] <code>task traceability:check</code> passes (if applicable)</li><li>[ ] Code comments link to affected spec IDs (e.g., <code>// CIV-0100: Economy.market_clear()</code>)</li><li>[ ] No new lint suppressions without inline justification</li><li>[ ] No fallback/compat/silent-failure code patterns</li><li>[ ] CHANGELOG.md updated (brief entry)</li><li>[ ] Determinism preserved (no stochastic changes without logging seed state)</li></ul><hr><h2 id="governance-evolution" tabindex="-1">Governance Evolution <a class="header-anchor" href="#governance-evolution" aria-label="Permalink to &quot;Governance Evolution&quot;">​</a></h2><p>When work touches a governance domain (quality, testing, determinism, traceability):</p><ol><li><strong>Check</strong> existing governance docs (above)</li><li><strong>Follow</strong> the established pattern</li><li><strong>Propose updates</strong> if governance is missing or unclear</li><li><strong>Write a conversation dump</strong> to <code>docs/research/CONVERSATION_DUMP_YYYY-MM-DD.md</code> when closing planning work</li></ol><hr><h2 id="quick-links" tabindex="-1">Quick Links <a class="header-anchor" href="#quick-links" aria-label="Permalink to &quot;Quick Links&quot;">​</a></h2><ul><li><strong>Run quality gates:</strong> <code>task quality</code></li><li><strong>Check work stream:</strong> <code>cat docs/reference/WORK_STREAM.md</code></li><li><strong>List specs:</strong> <code>task spec:list</code></li><li><strong>Validate specs:</strong> <code>task spec:validate</code></li><li><strong>Parpour planning:</strong> <code>/Users/kooshapari/temp-PRODVERCEL/485/kush/parpour/NEXT_STEPS.md</code></li><li><strong>Trace reference:</strong> <code>/Users/kooshapari/kush/trace/CLAUDE.md</code></li></ul><hr><p><strong>Last Updated:</strong> 2026-02-21 <strong>Status:</strong> ACTIVE</p>',78)])])}const u=e(n,[["render",i]]);export{p as __pageData,u as default};
